        } : null;
        info.toyear = toyear ? {
            value: toyear.value,
            options: Array.from(toyear.options).slice(-10).map(o => o.value)
        } : null;

        // Region select
        const regions = document.getElementById('regions');
        info.regions = regions ? {
            value: regions.value,
            options: Array.from(regions.options).map(o => ({value: o.value, text: o.text}))
        } : null;

        // Year slider editable spans
        const editableSpans = document.querySelectorAll('[contenteditable="true"]');
        info.editableSpans = Array.from(editableSpans).map(s => ({
            id: s.id, text: s.textContent.trim(), inputmode: s.getAttribute('inputmode')
