{"file_path": "/tmp/isolated_workspace_1091/extract_sjtu_ai.py", "content": """"
CSRankings SJTU AI Field Data Extractor
========================================
Uses Playwright (sync API) to:
  - Visit csrankings.org
  - Filter: year 2020-2025, region World, AI fields only
    (Artificial intelligence, Computer vision, Machine learning,
     Natural language processing, The Web & information retrieval)
  - Extract SJTU's rank / count / faculty
  - Output a single JSON object to stdout (no other output)

Implementation notes (from live DOM analysis):
  - The site uses AngularJS + noUiSlider; hash routing encodes filter state
  - Hash URL format:
      /#/fromyear/YYYY/toyear/YYYY/index?<area_flags>&<region>
  - Area flags: ai, vision, mlmining, nlp, inforet  (for AI subfields)
  - Region flag: world
  - Year spans (#year-display-from / #year-display-to) are contenteditable
    — click-triple + type is the only reliable way to change them
  - A Shepherd.js tour overlay blocks clicks on first load; must be dismissed
  - Rank is in <td class="rank-cell">; institution name is in a <span> (no
    special CSS class); count/faculty are in <td align="right">
"""

import json
import os
import re
import sys

os.environ.setdefault("PLAYWRIGHT_BROWSERS_PATH", "/opt/pw-browsers")

from playwright.sync_api import sync_playwright, TimeoutError as PWTimeout

# ── Constants ─────────────────────────────────────────────────────────────────

CHROMIUM_EXEC = "/opt/pw-browsers/chromium-1208/chrome-linux64/chrome"

# Direct hash URL: AI subfields + world region (year will be set separately)
BASE_URL = (
    "https://csrankings.org/#/index"
    "?ai&vision&mlmining&nlp&inforet&world"
)

FROM_YEAR = "2020"
TO_YEAR   = "2025"


# ── Helpers ───────────────────────────────────────────────────────────────────

def dismiss_shepherd_tour(page) -> None:
    """Dismiss the Shepherd.js onboarding tour if it is visible."""
    try:
        page.evaluate("""() => {
            // Try the built-in cancel button first
            const btn = document.querySelector(
                '.shepherd-cancel-icon, .shepherd-button-secondary'
            );
            if (btn) btn.click();
            // Forcibly remove any remaining overlay / tour elements
            document.querySelectorAll(
                '.shepherd-element, .shepherd-modal-overlay-container'
            ).forEach(el => el.remove());
            document.body.classList.remove('shepherd-has-active-tour');
        }""")
    except Exception:
        pass  # not critical


def set_year_span(page, span_id: str, year: str) -> None:
    """
    Edit a contenteditable year display span.
    Triple-click selects all existing text; then we type the new value.
    """
    locator = page.locator(f"#{span_id}")
    locator.click(click_count=3, timeout=10_000)
    page.keyboard.type(year)
    page.keyboard.press("Enter")


def wait_for_row_count_change(page, previous: int, timeout_ms: int = 12_000) -> None:
    """Wait until the ranking table row count differs from *previous*."""
    try:
        page.wait_for_function(
            "(prev) => document.querySelectorAll('#ranking tbody tr').length !== prev",
            arg=previous,
            timeout=timeout_ms,
        )
    except PWTimeout:
        pass  # may already be in the right state


def get_row_count(page) -> int:
    return page.evaluate(
        "() => document.querySelectorAll('#ranking tbody tr').length"
    )


# ── Main ──────────────────────────────────────────────────────────────────────

def main() -> None:
    with sync_playwright() as pw:
        browser = pw.chromium.launch(
            headless=True,
            executable_path=CHROMIUM_EXEC,
            args=["--no-sandbox", "--disable-setuid-sandbox"],
        )
        context = browser.new_context()
        page = context.new_page()

        # ── 1. Navigate to the pre-filtered URL (AI fields + World) ──────────
        page.goto(BASE_URL, wait_until="domcontentloaded", timeout=60_000)

        # Wait for at least one ranking row to appear
        page.wait_for_selector("#ranking tbody tr", timeout=30_000)

        # ── 2. Dismiss the Shepherd.js tour overlay ───────────────────────────
        dismiss_shepherd_tour(page)
        page.wait_for_timeout(300)

        # ── 3. Set year range via contenteditable spans ───────────────────────
        prev_rows = get_row_count(page)
        set_year_span(page, "year-display-from", FROM_YEAR)
        page.wait_for_timeout(800)

        prev_rows = get_row_count(page)
        set_year_span(page, "year-display-to", TO_YEAR)
        wait_for_row_count_change(page, prev_rows, timeout_ms=10_000)

        # Extra settle time for rendering
        page.wait_for_timeout(1_500)

        # ── 4. Capture final URL ──────────────────────────────────────────────
        final_url = page.url

        # ── 5. Locate Shanghai Jiao Tong University in the ranking table ──────
        sjtu_data = page.evaluate("""() => {
            const rows = document.querySelectorAll('#ranking tbody tr');
            for (const row of rows) {
                const cells = row.querySelectorAll('td');
                if (cells.length < 4) continue;

                // Institution cell (index 1) may contain spans / images / links.
                // We walk its child nodes looking for a text span with the name.
                const cell1 = cells[1];
                const nameSpan = Array.from(cell1.querySelectorAll('span')).find(
                    s => s.textContent.trim().includes('Shanghai Jiao Tong')
                );
                if (!nameSpan) continue;

                const rankText  = cells[0].textContent.trim();
                const countText = cells[2].textContent.trim();
                const facText   = cells[3].textContent.trim();

                return {
                    institution: nameSpan.textContent.trim(),
                    rank_raw:    rankText,
                    count_raw:   countText,
                    faculty_raw: facText,
                };
            }
            return null;
        }""")

        browser.close()

    # ── 6. Parse raw strings ──────────────────────────────────────────────────
    if sjtu_data is None:
        result = {
            "final_url": final_url,
            "error": "Shanghai Jiao Tong University not found in the filtered table",
            "data": None,
        }
        print(json.dumps(result, ensure_ascii=False, indent=2))
        sys.exit(1)

    # Rank: strip non-digits (handles "=" tie prefix, whitespace, etc.)
    rank_clean = re.sub(r"[^\d]", "", sjtu_data["rank_raw"])
    rank_val   = int(rank_clean) if rank_clean else None

    # Count: float
    try:
        count_val = float(sjtu_data["count_raw"].replace(",", ""))
    except ValueError:
        count_val = sjtu_data["count_raw"]

    # Faculty: int
    try:
        fac_val = int(re.sub(r"[^\d]", "", sjtu_data["faculty_raw"]))
    except ValueError:
        fac_val = sjtu_data["faculty_raw"]

    result = {
        "final_url": final_url,
        "data": {
            "institution": sjtu_data["institution"],
            "rank":        rank_val,
            "count":       count_val,
            "faculty":     fac_val,
        },
    }
    print(json.dumps(result, ensure_ascii=False, indent=2))


if __name__ == "__main__":
    main()
"}

