    const btn = document.querySelector(
        '.shepherd-cancel-icon, .shepherd-button-secondary'
    );
    if (btn) btn.click();
    document.querySelectorAll(
        '.shepherd-element, .shepherd-modal-overlay-container'
    ).forEach(el => el.remove());
    document.body.classList.remove('shepherd-has-active-tour');
}"""


# ── Helpers ───────────────────────────────────────────────────────────────────

def dismiss_shepherd_tour(page) -> None:
