    try:
        page.evaluate(_DISMISS_JS)
    except Exception:
        pass


def set_year_span(page, span_id: str, year: str) -> None:
    """
    Edit a contenteditable year display span.
    Dismisses any tour overlay first, then triple-clicks to select all
    existing text and types the new year value.
    """
    dismiss_shepherd_tour(page)
    page.wait_for_timeout(200)
    locator = page.locator(f"#{span_id}")
    locator.click(click_count=3, timeout=10_000)
    page.keyboard.type(year)
    page.keyboard.press("Enter")


