    """Wait until the #ranking tbody row count changes from *previous*."""
    try:
        page.wait_for_function(
            "(prev) => document.querySelectorAll('#ranking tbody tr').length !== prev",
            arg=previous,
            timeout=timeout_ms,
        )
    except PWTimeout:
        pass  # table may already be in the right state


